import {
  createContext,
  useContext,
  useEffect,
  useState,
} from "react";

import axios from "../api/axios";

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [token, setToken] = useState(null);
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  // -----------------------------
  // Decode JWT Payload
  // -----------------------------
  const decodeToken = (jwtToken) => {
    try {
      const payload = jwtToken.split(".")[1];
      return JSON.parse(atob(payload));
    } catch {
      return null;
    }
  };

  // -----------------------------
  // Check Token Expiry
  // -----------------------------
  const isTokenExpired = (jwtToken) => {
    const decoded = decodeToken(jwtToken);

    if (!decoded || !decoded.exp) {
      return false;
    }

    return decoded.exp * 1000 < Date.now();
  };

  // -----------------------------
  // Login
  // -----------------------------
  const login = async (email, password, rememberMe) => {
    try {
      const response = await axios.post(
        process.env.REACT_APP_LOGIN_ENDPOINT,
        {
          email,
          password,
        }
      );

      const apiToken = response.data.token;

      // ReqRes returns a simple token (not JWT)
      // We'll simulate a JWT payload so expiry logic works.
      const payload = {
        name: "Rehan",
        email,
        role: "Admin",
        exp: Math.floor(Date.now() / 1000) + 60 * 60,
      };

      const fakeJwt =
        "header." +
        btoa(JSON.stringify(payload)) +
        ".signature";

      const finalToken = apiToken
        ? fakeJwt
        : fakeJwt;

      setToken(finalToken);

      setUser({
        name: "Rehan",
        email,
        role: "Admin",
      });

      if (rememberMe) {
        localStorage.setItem("token", finalToken);

        localStorage.setItem(
          "user",
          JSON.stringify({
            name: "Rehan",
            email,
            role: "Admin",
          })
        );
      }

      return {
        success: true,
      };
    } catch (error) {
      let message = "Login Failed";

      if (!error.response) {
        message = "Network Error";
      } else if (error.response.status === 400) {
        message = "Invalid Email or Password";
      } else if (error.response.status === 401) {
        message = "Unauthorized";
      } else if (error.response.status >= 500) {
        message = "Server Error";
      }

      return {
        success: false,
        message,
      };
    }
  };

  // -----------------------------
  // Logout
  // -----------------------------
  const logout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");

    setToken(null);
    setUser(null);
  };

  // -----------------------------
  // Restore Login
  // -----------------------------
  useEffect(() => {
    const storedToken = localStorage.getItem("token");
    const storedUser = localStorage.getItem("user");

    if (!storedToken) {
      setLoading(false);
      return;
    }

    if (isTokenExpired(storedToken)) {
      logout();
      setLoading(false);
      return;
    }

    setToken(storedToken);

    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }

    setLoading(false);
  }, []);

  // -----------------------------
  // Auto Logout on Expiry
  // -----------------------------
  useEffect(() => {
    if (!token) return;

    const decoded = decodeToken(token);

    if (!decoded?.exp) return;

    const expiresIn =
      decoded.exp * 1000 - Date.now();

    if (expiresIn <= 0) {
      logout();
      return;
    }

    const timer = setTimeout(() => {
      logout();
      alert("Session Expired");
    }, expiresIn);

    return () => clearTimeout(timer);
  }, [token]);

  return (
    <AuthContext.Provider
      value={{
        token,user,loading, login, logout,isAuthenticated: !!token,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  return useContext(AuthContext);
};
